{
  "verses": [
    {
      "n": 2,
      "column": "left",
      "text": "Tas trefchajs Absaloms Dehls bija Iſtijus/ ta Dehls bi-\nMaēkas Dehls/ Talmaja ta ja Manaffus.\nKehnixa no Gesura Mettas.\nTas zettortajs Adonijus Agi-\ntas Dehls."
    },
    {
      "n": 3,
      "column": "left",
      "text": "Tas peektajs Sewatjus/\nno Abitalas/ tas ſestajs Jetre-\nams/ no winna Seewas Eglas."
    },
    {
      "n": 4,
      "column": "left",
      "text": "Schee ſefchi irr winnam\nEebroṇā dſimmuſchi/ jo wiꞥſch\nwaldija tur ſeptimus Gaddus\ndekijus.\nun ſefchus Mehneſchinis/ un trihs-\ndefinitis un trihs Gaddus wal-\ndija wiꞥſch Jeruſalemē."
    },
    {
      "n": 5,
      "column": "left",
      "text": "Un Schee irr winnam Je-\nrusaltemē dſimmuſchi/ Simeüs\ndajus/ un Senneazars/ un Je-\nun Sobabs/ un Nahtans/ un tamajus/Osamus un Nedabijus.\nSalamans tee tschetri/no Batsn-\nas Anunteka Mettas."
    },
    {
      "n": 6,
      "column": "left",
      "text": "Jebears/ un Elifamus/ un\nEeliwelets."
    },
    {
      "n": 7,
      "column": "left",
      "text": "Un Nogus/ un Newegs/\nun Japius."
    },
    {
      "n": 8,
      "column": "left",
      "text": "Un Eelisamus/ un Eeltja-\ndus/ un Eeltwalets tee dewint."
    },
    {
      "n": 9,
      "column": "left",
      "text": "Schee wiſſi irr Dahwida\nBehrni/ bes to leekeu Seewu\nBehrneem. Un Tahnara bija\nwinno Mahfa."
    },
    {
      "n": 10,
      "column": "left",
      "text": "Un Salamanca Dehls bi-\nja Rekabeams/ ta Dehls bija\nAbijus/ ta Dehls bija Ahus/ ta\nDehls bija Josawats."
    },
    {
      "n": 11,
      "column": "left",
      "text": "Ta Dehls bija Jorams/\nta Dehls bija Akasijus/ ta Dehls\nbija Joas."
    },
    {
      "n": 12,
      "column": "left",
      "text": "Ta Dehls bija Amazijus/\nta Dehls bija Asartjus/ ta Dehls\nbija Jotams."
    },
    {
      "n": 13,
      "column": "left",
      "text": "Ta Dehls bija Akas/ ta ja/ Odajus/ Elijasibs/ un Pla-\njus/"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Ta Dehls bija Amons/\nta Dehls bija Josijus."
    },
    {
      "n": 15,
      "column": "right",
      "text": "Un Josijus Behrni bija/\nJoanans tas pirmdſunnis/ Joja-\nkims tas ohtrs/ Zidekijus tas tre-\nchajs/ Sallums tas zettortajs."
    },
    {
      "n": 16,
      "column": "right",
      "text": "Jojakima Behrni bija\nZekantius/ ta Dehls bija Zt-\ndekijus."
    },
    {
      "n": 17,
      "column": "right",
      "text": "Un Zekantius/ ( kas Zee-\ntunā bijts/) Behrni bija/ Se-\naltiels winna Dehls."
    },
    {
      "n": 18,
      "column": "right",
      "text": "Un Malkirams/ un Wa-\ndajus/ un Senneazars/ un Je-\ntamajus/Osamus un Nedabijus."
    },
    {
      "n": 19,
      "column": "right",
      "text": "Un Wadajus Behrni bi-\nja Zerubabels un Simejus. Un\nZerubabela Behrni bija Mesul-\nlams/ un Anantjus/ un Selou-\nnite winnu Mahfa."
    },
    {
      "n": 20,
      "column": "right",
      "text": "Un Asubus/ un Oēls/ un\nBerekijs/ un Asadijus/ Jusab-\nEses/ tee peezt."
    },
    {
      "n": 21,
      "column": "right",
      "text": "Un Ananijus Behrni bt-\nja/ Plattijus un Jesajus/ tee\nBehrni Rewajus/ tee Behrni\nArnana/ tee Behrni Obadijuē/\ntee Behrni Sakantjus."
    },
    {
      "n": 22,
      "column": "right",
      "text": "Un tee Behrni Sakanti-\nus bija Semajus. Un Sema-\njus Behrni bija Atus/ un Ji-\ngeats/ un Bariaks/ un Nearijus/\nun Sawats/ Sesus tee ſefchi."
    },
    {
      "n": 23,
      "column": "right",
      "text": "Un Nearijus Behrni bt-\nja Elioēnajus/ un Iſtijus/ un\nAfricains/ tee trihs."
    },
    {
      "n": 24,
      "column": "right",
      "text": "Un Elioēnajus Behrni bt-\n"
    }
  ],
  "confidence": "high",
  "notes": ""
}
